Code.Terraform:
```hcl
# Terraform：设置至少 3 个专用主节点
resource "aws_opensearch_domain" "<example_resource_name>" {
  domain_name = "<example_resource_name>"

  cluster_config {
    dedicated_master_enabled = true  # 关键：启用专用主节点
    dedicated_master_count   = 3     # 关键：确保至少有 3 个主节点
    dedicated_master_type    = "<instance_type>"  # 关键：启用主节点时必需
  }
}
```
